// Bring both ensures-`forall|i|` clauses into the proof context with matching
// triggers so z3 instantiates them in lockstep across the post1 and post2
// runs of `set_ref_count`.
assert(forall|i: int|
    #![trigger post1_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==>
        post1_self_.page_array@[i] =~= pre_self_.page_array@[i]);
assert(forall|i: int|
    #![trigger post2_self_.page_array@[i]]
    #![trigger pre_self_.page_array@[i]]
    0 <= i < NUM_PAGES && i != index ==>
        post2_self_.page_array@[i] =~= pre_self_.page_array@[i]);

// At the modified index, every field of the Page is pinned to the same value
// in both runs (each `=~=` the corresponding pre_self_ field, except
// `ref_count` which `=~=` the input `ref_count`), so the two pages are
// `=~=`-equal by structural extensionality.
assert(post1_self_.page_array@[index as int]
       =~= post2_self_.page_array@[index as int]);

// Pointwise equality across the entire valid index range, by case split on
// whether `i` is the modified index.
assert forall|i: int| 0 <= i < NUM_PAGES implies
    post1_self_.page_array@[i] =~= post2_self_.page_array@[i] by {
    if i == index as int {
        // Closed by the index-level equality above (and i == index as int
        // means the two indexing expressions denote the same element).
    } else {
        // i != index, so both foralls give
        //   post1_self_.page_array@[i] =~= pre_self_.page_array@[i]
        //   post2_self_.page_array@[i] =~= pre_self_.page_array@[i]
        // and transitivity closes the goal.
    }
}

// Sequence extensionality lifts pointwise equality to the array view.
assert(post1_self_.page_array@ =~= post2_self_.page_array@);
